+/// Optimize select with fneg and fcmp zero pattern.
+/// Optimize select with fneg and fcmp zero pattern.
+static Instruction *foldSelectFNegWithFCmpZero(FCmpInst &I, InstCombinerImpl &IC) {
+  Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1);
+  // Only handle compare with zero.
+  if (!match(Op1, m_AnyZeroFP()))
+    return nullptr;
+
+  Value *Cond, *TrueVal, *FalseVal;
+  if (!match(Op0, m_Select(m_Value(Cond), m_Value(TrueVal), m_Value(FalseVal))))
+    return nullptr;
+
+  // Determine if TrueVal/FalseVal are X and fneg(X) (in either order).
+  Value *X = nullptr;
+  if (match(FalseVal, m_FNeg(m_Specific(TrueVal))))
+    X = TrueVal;
+  else if (match(TrueVal, m_FNeg(m_Specific(FalseVal))))
+    X = FalseVal;
+  else
+    return nullptr;
+
+  // Now we have fabs(X) (or -fabs(X)). For equality predicates, fabs does not
+  // affect comparison with zero.
+  switch (I.getPredicate()) {
+  case FCmpInst::FCMP_OEQ:
+  case FCmpInst::FCMP_UEQ:
+  case FCmpInst::FCMP_ONE:
+  case FCmpInst::FCMP_UNE:
+  case FCmpInst::FCMP_ORD:
+  case FCmpInst::FCMP_UNO:
+    // Replace select with X, keeping same predicate.
+    return new FCmpInst(I.getPredicate(), X, Op1, "", &I);
+  default:
+    // For other predicates, we could convert to fabs and let foldFabsWithFcmpZero
+    // handle it. For now, return nullptr.
+    break;
+  }
+  return nullptr;
+}

 /// Optimize fabs(X) compared with zero.
 static Instruction *foldFabsWithFcmpZero(FCmpInst &I, InstCombinerImpl &IC) {
@@ -8067,7 +8106,8 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
       break;
   }
   }
-
+  if (Instruction *R = foldSelectFNegWithFCmpZero(I, *this))
+    return R;
   if (Instruction *R = foldFabsWithFcmpZero(I, *this))
     return R;

